                                    <p className="text-[8px] text-gray-400">{(file.size / 1024).toFixed(0)} KB</p>
                                </div>
                                {/* طبقة تلميح عند الحوم */}
                                <div className="absolute inset-0 bg-brand-dark/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center no-print">
                                    <span className="bg-white/90 px-3 py-1 rounded-full text-[10px] font-bold text-brand-dark shadow-sm">معاينة</span>
                                </div>
                            </div>
                        ))}
                    </div>
                    {(!report.attachments || report.attachments.length === 0) && (
                        <p className="text-center py-10 text-gray-400 text-xs italic bg-gray-50/50 dark:bg-gray-800/30 rounded-2xl border border-dashed border-gray-200 dark:border-gray-700">لا توجد مرفقات مرتبطة بهذا التقرير.</p>
                    )}
                </section>

                {isManager && <AIReportAnalysis report={report} />}
            </div>

            {/* نافذة معاينة المرفق (Lightbox Viewer) */}
            {previewAttachment && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 no-print" onClick={() => setPreviewAttachment(null)}>
                    <button onClick={() => setPreviewAttachment(null)} className="absolute top-6 left-6 text-white/70 hover:text-white transition-colors bg-white/10 p-3 rounded-full hover:bg-white/20">
                        <XMarkIcon className="w-8 h-8" />
                    </button>

                    <div className="relative max-w-5xl w-full h-full flex flex-col items-center justify-center gap-6" onClick={e => e.stopPropagation()}>
                        {previewAttachment.type.startsWith('image/') ? (
                            <img src={previewAttachment.content} alt={previewAttachment.name} className="max-w-full max-h-[80vh] object-contain rounded-lg shadow-2xl animate-scale-in" />
