                            <div className="bg-white dark:bg-gray-800 p-12 rounded-[2rem] flex flex-col items-center gap-6 shadow-2xl animate-scale-in">
                                <DocumentTextIcon className="w-24 h-24 text-brand-light" />
                                <div className="text-center">
                                    <h3 className="text-xl font-bold dark:text-white mb-2">{previewAttachment.name}</h3>
