                                </div>
                                <a 
                                    href={previewAttachment.content} 
                                    download={previewAttachment.name}
                                    className="flex items-center gap-3 px-8 py-3 bg-brand-light text-white rounded-2xl font-bold shadow-xl shadow-brand-light/20 hover:scale-105 active:scale-95 transition-all"
                                >
                                    <DownloadIcon className="w-6 h-6" />
                                    تحميل المستند للمراجعة
                                </a>
                            </div>
                        )}
                        <p className="text-white/60 text-sm font-medium bg-white/5 px-6 py-2 rounded-full border border-white/10">{previewAttachment.name}</p>
                    </div>
                </div>
            )}
        </div>
    );
};

