                                    {isManager && (
                                        <td className="px-4 py-3 text-center no-print">
                                            {!task.isDeleted && (
                                                <button onClick={() => handleTaskDelete(task.id)} className="text-red-400 hover:text-red-600 p-1.5 hover:bg-red-50 rounded-lg transition-all">
                                                    <TrashIcon className="w-4 h-4" />
                                                </button>
