export default ReportsView;

import React, { useState, useMemo } from 'react';
import { useData } from '../context/DataContext';
import { Role, User, Report } from '../types';
import Avatar from './Avatar';
import EmployeeReportsView from './EmployeeReportsView';
import ReportDetail from './ReportDetail';
import ArrowRightIcon from './icons/ArrowRightIcon';
import DownloadIcon from './icons/DownloadIcon';
import UnitFolder from './UnitFolder';
import ArrowPathIcon from './icons/ArrowPathIcon';
import TrashIcon from './icons/TrashIcon';
import ConfirmModal from './ConfirmModal';

const ReportsView: React.FC = () => {
    const { users, reports, markReportAsViewed, deleteReport } = useData();
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedEmployee, setSelectedEmployee] = useState<User | null>(null);
    const [viewingReport, setViewingReport] = useState<Report | null>(null);
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [showOnlyUnread, setShowOnlyUnread] = useState(false);
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

    const employees = useMemo(() => users.filter(u => u.role === Role.EMPLOYEE), [users]);

    const getUnreadCount = (employeeId: string): number => {
        return reports.filter(r => r.userId === employeeId && !r.isViewedByManager && r.status === 'submitted').length;
    };

    const filteredEmployees = useMemo(() => {
        let employeesToShow = employees;
        if (searchTerm) {
            employeesToShow = employeesToShow.filter(employee =>
                employee.fullName.toLowerCase().includes(searchTerm.toLowerCase())
            );
        }
        if (showOnlyUnread) {
            employeesToShow = employeesToShow.filter(employee => getUnreadCount(employee.id) > 0);
        }
        if (dateFrom || dateTo) {
            const from = dateFrom || '0000-01-01';
            const to = dateTo || '9999-12-31';
            const employeesWithReportsInRange = new Set(
                reports
                    .filter(report => report.date >= from && report.date <= to)
                    .map(report => report.userId)
            );
            employeesToShow = employeesToShow.filter(employee => employeesWithReportsInRange.has(employee.id));
        }
        return employeesToShow;
    }, [employees, reports, searchTerm, showOnlyUnread, dateFrom, dateTo]);

    const unitOrder = ['وحدة التمكين الفني', 'وحدة التنسيق الفني'];

    const groupedEmployees = useMemo(() => {
        const groups: { [key: string]: User[] } = {
            'وحدة التمكين الفني': [],
            'وحدة التنسيق الفني': [],
        };
        filteredEmployees.forEach(employee => {
            if (employee.unit && (employee.unit === 'وحدة التمكين الفني' || employee.unit === 'وحدة التنسيق الفني')) {
                groups[employee.unit].push(employee);
            }
        });
        return groups;
    }, [filteredEmployees]);


    const handleViewReport = (report: Report) => {
        if (!report.isViewedByManager) {
            markReportAsViewed(report.id);
        }
        setViewingReport(report);
    };

    const handleResetFilters = () => {
        setSearchTerm('');
        setDateFrom('');
        setDateTo('');
        setShowOnlyUnread(false);
    };

    const handleDeleteReport = async () => {
        if (viewingReport) {
            await deleteReport(viewingReport.id);
            setShowDeleteConfirm(false);
            setViewingReport(null);
        }
    };

    // 1. حالة عرض تفاصيل تقرير معين
    if (viewingReport && selectedEmployee) {
        return (
            <div id="printable-area" className="bg-white dark:bg-gray-800 rounded-3xl shadow-xl overflow-hidden animate-fade-in border dark:border-gray-700">
                <div className="flex flex-col md:flex-row items-center justify-between p-5 bg-gray-50 dark:bg-gray-900/50 border-b dark:border-gray-700 gap-4 no-print">
                     <div className="flex items-center gap-4">
                         <Avatar src={selectedEmployee.profilePictureUrl} name={selectedEmployee.fullName} size={44} />
                         <div>
                            <h3 className="text-sm md:text-base font-bold text-brand-dark dark:text-gray-100 leading-tight">التقرير #{viewingReport.sequenceNumber}: {selectedEmployee.fullName}</h3>
                            <p className="text-[10px] text-gray-500">{viewingReport.date} - {viewingReport.day}</p>
                         </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setShowDeleteConfirm(true)} className="p-2 text-red-500 hover:bg-red-50 rounded-lg">
                            <TrashIcon className="w-5 h-5" />
                        </button>
                        <button onClick={() => window.print()} className="flex items-center gap-2 px-4 py-1.5 bg-brand-light text-white rounded-lg font-bold shadow-md text-xs">
                            <DownloadIcon className="w-4 h-4" />
                            <span>حفظ كـ PDF</span>
                        </button>
                        <button onClick={() => setViewingReport(null)} className="p-2 text-gray-400 hover:text-gray-700">
                            <ArrowRightIcon className="w-7 h-7" />
                        </button>
                    </div>
                </div>

                {/* ترويسة الطباعة الرسمية */}
                <div className="hidden print:block p-8 border-b-2 border-black">
                    <div className="flex justify-between items-start">
                        <div className="text-right">
                            <h1 className="text-sm font-bold">قسم التنمية والتأهيل الاجتماعي للشباب</h1>
                            <h2 className="text-xs font-bold text-gray-700">شعبة الفنون والمسرح</h2>
                            <p className="text-[10px] mt-2 font-bold">المنتسب: {selectedEmployee.fullName}</p>
                        </div>
                        <div className="text-left text-[10px]">
                             <p className="font-bold">التاريخ: {viewingReport.date}</p>
                             <p>التسلسل: {viewingReport.sequenceNumber}</p>
                        </div>
                    </div>
                </div>

                <div className="bg-white dark:bg-gray-900">
                    <ReportDetail report={viewingReport} user={selectedEmployee} viewerRole={Role.MANAGER} />
                </div>

                {showDeleteConfirm && (
                    <ConfirmModal
                        title="حذف التقرير"
                        message="سيتم حذف التقرير نهائياً من سجلات المنتسب."
                        onConfirm={handleDeleteReport}
                        onCancel={() => setShowDeleteConfirm(false)}
                        confirmText="تأكيد الحذف"
                        confirmButtonClass="bg-red-600"
                    />
                )}
            </div>
        );
    }

    // 2. حالة عرض قائمة تقارير منتسب معين (الملف الشخصي للمنتسب)
    if (selectedEmployee) {
        return (
            <EmployeeReportsView 
                employee={selectedEmployee} 
                onViewReport={handleViewReport} 
                onBack={() => setSelectedEmployee(null)} 
            />
        );
    }

    // 3. الحالة الافتراضية: عرض مجلدات الوحدات والبحث
    const hasFilteredResults = Object.keys(groupedEmployees).some(key => groupedEmployees[key].length > 0);

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="p-5 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700 space-y-4">
                <div className="flex flex-col md:flex-row gap-4 items-end">
                    <div className="flex-1 w-full">
                        <label className="block text-xs font-bold text-gray-500 mb-1">البحث عن منتسب</label>
                        <input
                            type="text"
                            placeholder="اكتب اسم المنتسب هنا..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full px-4 py-2 text-sm border dark:border-gray-600 rounded-xl bg-gray-50 dark:bg-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-brand-light outline-none"
                        />
                    </div>
                    <div className="flex items-center gap-2">
                        <div className="flex items-center h-10 px-4 bg-gray-100 dark:bg-gray-700 rounded-xl">
                            <input id="unread-only" type="checkbox" checked={showOnlyUnread} onChange={e => setShowOnlyUnread(e.target.checked)} className="h-4 w-4 rounded border-gray-300 text-brand-light" />
                            <label htmlFor="unread-only" className="mr-2 text-xs font-bold text-gray-600 dark:text-gray-300 cursor-pointer">غير مقروءة</label>
                        </div>
                        <button onClick={handleResetFilters} className="h-10 px-4 bg-gray-100 dark:bg-gray-600 rounded-xl text-xs font-bold text-gray-500 flex items-center gap-2 hover:bg-gray-200">
                            <ArrowPathIcon className="w-4 h-4" /> إعادة تعيين
                        </button>
                    </div>
                </div>

                <div className="grid grid-cols-2 md:grid-cols-2 gap-4 pt-4 border-t dark:border-gray-700">
                    <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1 uppercase">من تاريخ</label>
                        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="w-full px-3 py-2 text-xs border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 dark:text-white" />
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-gray-400 mb-1 uppercase">إلى تاريخ</label>
                        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} min={dateFrom} className="w-full px-3 py-2 text-xs border dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 dark:text-white" />
                    </div>
                </div>
            </div>

            {hasFilteredResults ? (
                <div className="space-y-6">
                    {unitOrder.map(unitName => {
                        const employeesInUnit = groupedEmployees[unitName];
                        if (!employeesInUnit || employeesInUnit.length === 0) return null;
                        return (
                            <UnitFolder 
                                key={unitName} 
                                unitName={unitName} 
                                employees={employeesInUnit} 
                                getUnreadCount={getUnreadCount} 
                                onEmployeeClick={(emp) => setSelectedEmployee(emp)} 
                            />
                        );
                    })}
                </div>
            ) : (
                <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-2xl border border-dashed border-gray-200 dark:border-gray-700">
                    <p className="text-gray-400 text-sm">لا توجد نتائج مطابقة للبحث حالياً.</p>
                </div>
            )}
        </div>
    );
};

export default ReportsView;

import { User, Report, Announcement, DirectTask, Role } from '../types';
import { supabase, isSupabaseConfigured } from './supabaseConfig';

interface AppState {
    users: User[];
    reports: Report[];
    announcements: Announcement[];
    directTasks: DirectTask[];
    isCloud: boolean;
}

const generateId = () => crypto.randomUUID();

export const mapUser = (row: any): User => ({
    id: row.id,
    fullName: row.full_name,
    badgeNumber: row.badge_number,
    username: row.username,
    password: row.password,
    role: row.role as Role,
    jobTitle: row.job_title,
    unit: row.unit,
    profilePictureUrl: row.profile_picture_url
});

export const mapReport = (row: any): Report => ({
    id: row.id,
    userId: row.user_id,
    sequenceNumber: row.sequence_number,
    date: row.date,
    day: row.day,
    tasks: row.tasks || [],
    accomplished: row.accomplished,
    notAccomplished: row.not_accomplished,
    attachments: row.attachments || [],
    managerComment: row.manager_comment,
    isViewedByManager: row.is_viewed_by_manager,
    isCommentReadByEmployee: row.is_comment_read_by_employee,
    rating: row.rating,
    status: row.status
});

export const mapAnnouncement = (row: any): Announcement => ({
    id: row.id,
    content: row.content,
    date: row.date,
    readBy: row.read_by || []
});

export const mapDirectTask = (row: any): DirectTask => ({
    id: row.id,
    managerId: row.manager_id,
    employeeId: row.employee_id,
    content: row.content,
    sentAt: row.sent_at,
    status: row.status,
    acknowledgedAt: row.acknowledged_at,
    rejectionReason: row.rejection_reason,
    isReadByEmployee: row.is_read_by_employee
});

export const fetchInitialData = async (): Promise<AppState> => {
    if (!isSupabaseConfigured()) throw new Error("Supabase is not configured.");
    const [usersRes, reportsRes, annRes, tasksRes] = await Promise.all([
        supabase.from('users').select('*'),
        supabase.from('reports').select('*'),
        supabase.from('announcements').select('*'),
        supabase.from('direct_tasks').select('*')
    ]);

    return {
        users: (usersRes.data || []).map(mapUser),
        reports: (reportsRes.data || []).map(mapReport),
        announcements: (annRes.data || []).map(mapAnnouncement),
        directTasks: (tasksRes.data || []).map(mapDirectTask),
        isCloud: true
    };
};

export const subscribeToAllChanges = (onUpdate: (payload: any) => void) => {
    const channel = supabase
        .channel('schema-db-changes')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'reports' }, (p) => onUpdate({ table: 'reports', ...p }))
        .on('postgres_changes', { event: '*', schema: 'public', table: 'direct_tasks' }, (p) => onUpdate({ table: 'direct_tasks', ...p }))
        .on('postgres_changes', { event: '*', schema: 'public', table: 'announcements' }, (p) => onUpdate({ table: 'announcements', ...p }))
        .on('postgres_changes', { event: '*', schema: 'public', table: 'users' }, (p) => onUpdate({ table: 'users', ...p }))
        .subscribe();

    return () => { supabase.removeChannel(channel); };
};

export const createReport = async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>): Promise<Report> => {
    // التعديل هنا: جلب أعلى تسلسل للمنتسب المحدد فقط
    const { data: maxSeqData } = await supabase
        .from('reports')
        .select('sequence_number')
        .eq('user_id', report.userId)
        .eq('status', 'submitted')
        .order('sequence_number', { ascending: false })
        .limit(1);

    const maxSeq = maxSeqData && maxSeqData.length > 0 ? maxSeqData[0].sequence_number : 0;
    const newId = generateId();
    const dbReport = {
        id: newId, 
        user_id: report.userId, 
        sequence_number: maxSeq + 1, // التسلسل الجديد الخاص بالمنتسب
        date: report.date, 
        day: report.day,
        tasks: report.tasks, 
        accomplished: report.accomplished, 
        not_accomplished: report.notAccomplished,
        attachments: report.attachments, 
        status: 'submitted', 
        is_viewed_by_manager: false, 
        is_comment_read_by_employee: false
    };
    const { error } = await supabase.from('reports').insert(dbReport);
    if (error) throw error;
    return { ...report, id: newId, status: 'submitted', sequenceNumber: maxSeq + 1 } as Report;
};

export const saveOrUpdateDraft = async (draft: Partial<Report>): Promise<Report> => {
    const dbPayload = {
        user_id: draft.userId, date: draft.date, day: draft.day, tasks: draft.tasks || [],
        accomplished: draft.accomplished || '', not_accomplished: draft.notAccomplished || '',
        attachments: draft.attachments || [], status: 'draft', sequence_number: null
    };

    if (draft.id && !draft.id.startsWith('temp-')) {
        const { error } = await supabase.from('reports').update(dbPayload).eq('id', draft.id);
        if (error) throw error;
        return { ...draft, status: 'draft' } as Report;
    } else {
        const newId = generateId();
        const { error } = await supabase.from('reports').insert({ id: newId, ...dbPayload });
        if (error) throw error;
        return { ...draft, id: newId, status: 'draft' } as Report;
    }
};

export const updateReport = async (updatedReport: Report): Promise<Report> => {
    const { error } = await supabase.from('reports').update({
        tasks: updatedReport.tasks, accomplished: updatedReport.accomplished,
        not_accomplished: updatedReport.notAccomplished, attachments: updatedReport.attachments,
        manager_comment: updatedReport.managerComment, rating: updatedReport.rating,
        status: updatedReport.status, is_viewed_by_manager: updatedReport.isViewedByManager,
        is_comment_read_by_employee: updatedReport.isCommentReadByEmployee
    }).eq('id', updatedReport.id);
    if (error) throw error;
    return updatedReport;
};

export const deleteReport = async (reportId: string): Promise<void> => {
    await supabase.from('reports').delete().eq('id', reportId);
};

export const markReportAsViewed = async (reportId: string): Promise<void> => {
    await supabase.from('reports').update({ is_viewed_by_manager: true }).eq('id', reportId);
};

export const markCommentAsRead = async (reportId: string): Promise<void> => {
    await supabase.from('reports').update({ is_comment_read_by_employee: true }).eq('id', reportId);
};

export const createDirectTask = async (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>): Promise<DirectTask> => {
    const newId = generateId();
    const dbTask = { id: newId, manager_id: task.managerId, employee_id: task.employeeId, content: task.content, sent_at: new Date().toISOString(), status: 'pending', is_read_by_employee: false };
    const { error } = await supabase.from('direct_tasks').insert(dbTask);
    if (error) throw error;
    return { ...task, id: newId, sentAt: dbTask.sent_at, status: 'pending', isReadByEmployee: false };
};

export const updateDirectTaskStatus = async (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string): Promise<void> => {
    const updates: any = { status };
    if (rejectionReason) updates.rejection_reason = rejectionReason;
    if (status === 'acknowledged') updates.acknowledged_at = new Date().toISOString();
    await supabase.from('direct_tasks').update(updates).eq('id', taskId);
};

export const markDirectTaskAsRead = async (taskId: string): Promise<void> => {
    await supabase.from('direct_tasks').update({ is_read_by_employee: true }).eq('id', taskId);
};

export const createUser = async (user: Omit<User, 'id'>): Promise<User> => {
    const newId = generateId();
    await supabase.from('users').insert({ id: newId, full_name: user.fullName, badge_number: user.badgeNumber, username: user.username, password: user.password, role: user.role, job_title: user.jobTitle, unit: user.unit, profile_picture_url: user.profilePictureUrl });
    return { ...user, id: newId };
};

export const updateUser = async (updatedUser: User): Promise<User> => {
    await supabase.from('users').update({ full_name: updatedUser.fullName, badge_number: updatedUser.badgeNumber, username: updatedUser.username, password: updatedUser.password, role: updatedUser.role, job_title: updatedUser.jobTitle, unit: updatedUser.unit, profile_picture_url: updatedUser.profilePictureUrl }).eq('id', updatedUser.id);
    return updatedUser;
};

export const deleteUser = async (userId: string): Promise<void> => {
    await supabase.from('reports').delete().eq('user_id', userId);
    await supabase.from('users').delete().eq('id', userId);
};

export const createAnnouncement = async (content: string): Promise<Announcement> => {
    const newId = generateId();
    const { error } = await supabase.from('announcements').insert({ id: newId, content, date: new Date().toISOString(), read_by: [] });
    if (error) throw error;
    return { id: newId, content, date: new Date().toISOString(), readBy: [] };
};

export const updateAnnouncement = async (announcementId: string, content: string): Promise<Announcement> => {
    await supabase.from('announcements').update({ content }).eq('id', announcementId);
    return { id: announcementId, content } as Announcement;
};

export const deleteAnnouncement = async (announcementId: string): Promise<void> => {
    await supabase.from('announcements').delete().eq('id', announcementId);
};

export const markAnnouncementAsRead = async (announcementId: string, userId: string): Promise<void> => {
    const { data } = await supabase.from('announcements').select('read_by').eq('id', announcementId).single();
    if (data) {
        const currentReadBy = data.read_by || [];
        if (!currentReadBy.some((r: any) => r.userId === userId)) {
            const updatedReadBy = [...currentReadBy, { userId, readAt: new Date().toISOString() }];
            await supabase.from('announcements').update({ read_by: updatedReadBy }).eq('id', announcementId);
        }
    }
};

import React, { createContext, useState, useContext, ReactNode, useMemo, useCallback, useEffect, useRef } from 'react';
import { User, Report, Announcement, DirectTask } from '../types';
import * as api from '../services/apiService';

interface AppState {
    users: User[];
    reports: Report[];
    announcements: Announcement[];
    directTasks: DirectTask[];
}

interface DataContextType extends AppState {
    isDataLoading: boolean;
    isCloud: boolean;
    error: string | null;
    isSyncing: boolean;
    refreshData: () => Promise<void>;
    notification: { message: string, type: 'info' | 'success', id: number } | null;
    clearNotification: () => void;
    getUserById: (id: string) => User | undefined;
    addReport: (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => Promise<void>;
    updateReport: (updatedReport: Report) => Promise<void>;
    saveOrUpdateDraft: (draft: Partial<Report>) => Promise<void>;
    deleteReport: (reportId: string) => Promise<void>;
    markReportAsViewed: (reportId: string) => Promise<void>;
    markCommentAsRead: (reportId: string) => Promise<void>;
    addUser: (user: Omit<User, 'id'>) => Promise<void>;
    updateUser: (user: User) => Promise<void>;
    deleteUser: (userId: string) => Promise<void>;
    addAnnouncement: (content: string) => Promise<void>;
    updateAnnouncement: (announcementId: string, content: string) => Promise<void>;
    deleteAnnouncement: (announcementId: string) => Promise<void>;
    markAnnouncementAsRead: (announcementId: string, userId: string) => Promise<void>;
    addDirectTask: (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>) => Promise<void>;
    updateDirectTaskStatus: (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string) => Promise<void>;
    markDirectTaskAsRead: (taskId: string) => Promise<void>;
    unlockAudio: () => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

// نغمة التنبيه بصيغة Base64 لضمان عملها في كل الظروف
const NOTIFICATION_SOUND_BASE64 = "data:audio/wav;base64,UklGRl9vT19XQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YTdvT18AZm9vYmFyYmF6cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4cXV4";

export const DataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [appState, setAppState] = useState<AppState>({ users: [], reports: [], announcements: [], directTasks: [] });
    const [isDataLoading, setIsDataLoading] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isCloud, setIsCloud] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [notification, setNotification] = useState<{ message: string, type: 'info' | 'success', id: number } | null>(null);

    const audioRef = useRef<HTMLAudioElement | null>(null);
    const currentUserIdRef = useRef<string | null>(null);

    // تجهيز الصوت
    useEffect(() => {
        audioRef.current = new Audio('https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3'); // نغمة احترافية واضحة
        audioRef.current.load();
    }, []);

    const unlockAudio = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.play().then(() => {
                audioRef.current?.pause();
                if (audioRef.current) audioRef.current.currentTime = 0;
                console.log("Audio Unlocked for iOS/Android");
            }).catch(e => console.log("Audio unlock failed", e));
        }
    }, []);

    const playNotificationSound = useCallback(() => {
        if (audioRef.current) {
            audioRef.current.currentTime = 0;
            audioRef.current.play().catch(e => console.warn("Audio play blocked", e));
        }
    }, []);

    const clearNotification = useCallback(() => setNotification(null), []);

    const triggerNotification = useCallback((title: string, body: string, type: 'info' | 'success' = 'info') => {
        // 1. تنبيه منبثق داخل التطبيق
        setNotification({ message: body, type, id: Date.now() });

        // 2. صوت تنبيه
        playNotificationSound();

        // 3. تنبيه نظام المتصفح (للخلفية)
        if ("Notification" in window && Notification.permission === "granted") {
            try {
                const n = new Notification(title, { body, icon: 'https://img.icons8.com/fluency/192/task.png' });
                n.onclick = () => { window.focus(); n.close(); };
            } catch (e) {
                console.warn("Browser Notification failed", e);
            }
        }
    }, [playNotificationSound]);

    const loadData = useCallback(async (silent = false) => {
        if (!silent) setIsDataLoading(true);
        else setIsSyncing(true);
        try {
            const data = await api.fetchInitialData();
            setAppState({
                users: data.users,
                reports: data.reports,
                announcements: data.announcements,
                directTasks: data.directTasks
            });
            setIsCloud(data.isCloud);
        } catch (error: any) {
            console.error("Sync Error:", error);
            if (!silent) setError(error.message || "فشل الاتصال بقاعدة البيانات.");
        } finally {
            setIsDataLoading(false);
            setIsSyncing(false);
        }
    }, []);

    const refreshData = useCallback(async () => {
        await loadData(true);
    }, [loadData]);

    useEffect(() => {
        loadData();
        currentUserIdRef.current = localStorage.getItem('loggedInUserId') || sessionStorage.getItem('loggedInUserId');

        const unsubscribe = api.subscribeToAllChanges((payload) => {
            const { table, eventType, new: newRecord, old: oldRecord } = payload;

            setAppState(prev => {
                const newState = { ...prev };
                const loggedInUserId = localStorage.getItem('loggedInUserId') || sessionStorage.getItem('loggedInUserId');
                const currentUser = prev.users.find(u => u.id === loggedInUserId);

                if (table === 'reports') {
                    const mapped = api.mapReport(newRecord);
                    if (eventType === 'INSERT' || eventType === 'UPDATE') {
                        const existsIndex = prev.reports.findIndex(r => r.id === mapped.id);
                        const oldReport = existsIndex > -1 ? prev.reports[existsIndex] : null;

                        if (existsIndex > -1) newState.reports = prev.reports.map(r => r.id === mapped.id ? mapped : r);
                        else newState.reports = [mapped, ...prev.reports];

                        // منطق التنبيهات للتقارير
                        if (eventType === 'INSERT' && mapped.status === 'submitted' && currentUser?.role === 'manager') {
                            const sender = prev.users.find(u => u.id === mapped.userId);
                            triggerNotification('تقرير جديد', `أرسل ${sender?.fullName || 'منتسب'} تقريراً جديداً الآن.`);
                        }

                        // تنبيه للمنتسب إذا علق المدير
                        if (eventType === 'UPDATE' && mapped.userId === loggedInUserId && mapped.managerComment && mapped.managerComment !== oldReport?.managerComment) {
                            triggerNotification('توجيه جديد', 'لقد وضع المسؤول ملاحظات جديدة على تقريرك.', 'success');
                        }

                    } else if (eventType === 'DELETE') {
                        newState.reports = prev.reports.filter(r => r.id !== oldRecord.id);
                    }
                } else if (table === 'direct_tasks') {
                    const mapped = api.mapDirectTask(newRecord);
                    if (eventType === 'INSERT') {
                        newState.directTasks = [mapped, ...prev.directTasks];
                        if (mapped.employeeId === loggedInUserId) {
                            triggerNotification('مهمة عمل', 'وصلتك مهمة عمل فورية من المسؤول.', 'info');
                        }
                    } else if (eventType === 'UPDATE') {
                        newState.directTasks = prev.directTasks.map(t => t.id === mapped.id ? mapped : t);
                        // تنبيه للمدير إذا تم قبول المهمة
                        if (mapped.managerId === loggedInUserId && mapped.status !== 'pending') {
                            const emp = prev.users.find(u => u.id === mapped.employeeId);
                            triggerNotification('تحديث مهمة', `قام ${emp?.fullName.split(' ')[0]} بتحديث حالة المهمة.`);
                        }
                    }
                } else if (table === 'announcements') {
                    const mapped = api.mapAnnouncement(newRecord);
                    if (eventType === 'INSERT') {
                        newState.announcements = [mapped, ...prev.announcements];
                        triggerNotification('تعميم إداري', 'يوجد توجيه إداري جديد لجميع المنتسبين.', 'success');
                    }
                } else if (table === 'users') {
                    const mapped = api.mapUser(newRecord);
                    if (eventType === 'UPDATE') newState.users = prev.users.map(u => u.id === mapped.id ? mapped : u);
                }
                return newState;
            });
        });

        return () => { unsubscribe(); };
    }, [loadData, triggerNotification]);

    const getUserById = useCallback((id: string) => appState.users.find(u => u.id === id), [appState.users]);

    const saveOrUpdateDraft = useCallback(async (draft: Partial<Report>) => {
        const tempId = draft.id || `temp-${Date.now()}`;
        const tempDraft = { id: tempId, status: 'draft', ...draft } as Report;
        setAppState(prev => {
            const exists = prev.reports.find(r => r.id === draft.id);
            if (exists) return { ...prev, reports: prev.reports.map(r => r.id === draft.id ? { ...r, ...tempDraft } : r) };
            return { ...prev, reports: [tempDraft, ...prev.reports] };
        });
        try { await api.saveOrUpdateDraft(draft); } catch (error) { loadData(true); throw error; }
    }, [loadData]);

    const addReport = useCallback(async (report: Omit<Report, 'id' | 'sequenceNumber' | 'status'>) => {
        try { await api.createReport(report); } catch (error) { throw error; }
    }, []);

    const updateReport = useCallback(async (updatedReport: Report) => {
        setAppState(prev => ({ ...prev, reports: prev.reports.map(r => r.id === updatedReport.id ? updatedReport : r) }));
        try { await api.updateReport(updatedReport); } catch (error) { loadData(true); throw error; }
    }, [loadData]);

    const deleteReport = useCallback(async (reportId: string) => {
        setAppState(prev => ({ ...prev, reports: prev.reports.filter(r => r.id !== reportId) }));
        try { await api.deleteReport(reportId); } catch (error) { loadData(true); throw error; }
    }, [loadData]);

    const markReportAsViewed = useCallback(async (reportId: string) => api.markReportAsViewed(reportId), []);
    const markCommentAsRead = useCallback(async (reportId: string) => api.markCommentAsRead(reportId), []);
    const addUser = useCallback(async (user: Omit<User, 'id'>) => api.createUser(user), []);
    const updateUser = useCallback(async (updatedUser: User) => api.updateUser(updatedUser), []);
    const deleteUser = useCallback(async (userId: string) => api.deleteUser(userId), []);
    const addAnnouncement = useCallback(async (content: string) => api.createAnnouncement(content), []);
    const updateAnnouncement = useCallback(async (announcementId: string, content: string) => api.updateAnnouncement(announcementId, content), []);
    const deleteAnnouncement = useCallback(async (announcementId: string) => api.deleteAnnouncement(announcementId), []);
    const markAnnouncementAsRead = useCallback(async (announcementId: string, userId: string) => api.markAnnouncementAsRead(announcementId, userId), []);
    const addDirectTask = useCallback(async (task: Omit<DirectTask, 'id' | 'sentAt' | 'status' | 'isReadByEmployee'>) => api.createDirectTask(task), []);
    const updateDirectTaskStatus = useCallback(async (taskId: string, status: 'acknowledged' | 'rejected', rejectionReason?: string) => api.updateDirectTaskStatus(taskId, status, rejectionReason), []);
    const markDirectTaskAsRead = useCallback(async (taskId: string) => api.markDirectTaskAsRead(taskId), []);

    const value = useMemo(() => ({
        ...appState, isDataLoading, isCloud, error, isSyncing, refreshData, notification, clearNotification, getUserById, addReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead, unlockAudio
    }), [
        appState, isDataLoading, isCloud, error, isSyncing, refreshData, notification, clearNotification, getUserById, addReport, updateReport, saveOrUpdateDraft, deleteReport, markReportAsViewed,
        markCommentAsRead, addUser, updateUser, deleteUser, addAnnouncement, updateAnnouncement, deleteAnnouncement,
        markAnnouncementAsRead, addDirectTask, updateDirectTaskStatus, markDirectTaskAsRead, unlockAudio
    ]);

    return (
        <DataContext.Provider value={value}>
            {children}
        </DataContext.Provider>
    );
};

export const useData = (): DataContextType => {
    const context = useContext(DataContext);
    if (!context) throw new Error('useData must be used within a DataProvider');
    return context;
};

