const occasions: ReligiousOccasion[] = [
    { day: 1, month: 1, title: "رأس السنة الهجرية", type: 'general' },
    { day: 10, month: 1, title: "ذكرى عاشوراء (استشهاد الإمام الحسين ع)", type: 'sadness' },
    { day: 25, month: 1, title: "استشهاد الإمام السجاد (ع)", type: 'sadness' },
    { day: 7, month: 2, title: "استشهاد الإمام الحسن المجتبى (ع)", type: 'sadness' },
    { day: 20, month: 2, title: "زيارة الأربعين", type: 'sadness' },
    { day: 28, month: 2, title: "وفاة الرسول الأعظم (ص)", type: 'sadness' },
    { day: 17, month: 3, title: "ولادة النبي الأكرم (ص) والإمام الصادق (ع)", type: 'joy' },
    { day: 8, month: 4, title: "ولادة الإمام الحسن العسكري (ع)", type: 'joy' },
    { day: 5, month: 5, title: "ولادة السيدة زينب (ع)", type: 'joy' },
    { day: 13, month: 5, title: "استشهاد السيدة الزهراء (ع) - رواية", type: 'sadness' },
