export const getHijriDate = (offset: number = 0) => {
    const date = new Date();
    // تطبيق الإزاحة (Offset) لتعديل الهلال يدوياً إذا لزم الأمر
    date.setDate(date.getDate() + offset);

    const options: Intl.DateTimeFormatOptions = {
        day: 'numeric',
        month: 'numeric',
        year: 'numeric',
        calendar: 'islamic-uma',
    };

    const formatter = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-uma', options);
    const parts = formatter.formatToParts(date);

    const day = parseInt(parts.find(p => p.type === 'day')?.value || '0');
    const month = parseInt(parts.find(p => p.type === 'month')?.value || '0');
    const year = parts.find(p => p.type === 'year')?.value || '0';

    // الحصول على اسم الشهر الهجري بالعربي
    const monthNames = [
        "محرم الحرام", "صفر الخير", "ربيع الأول", "ربيع الثاني",
        "جمادى الأولى", "جمادى الآخرة", "رجب الأصب", "شعبان المعظم",
        "رمضان المبارك", "شوال المكرم", "ذو القعدة", "ذو الحجة"
    ];

    const occasion = occasions.find(o => o.day === day && o.month === month);

    return {
        day,
        month,
        monthName: monthNames[month - 1],
        year,
        fullDate: `${day} ${monthNames[month - 1]} ${year}`,
        occasion
    };
};

