/**
 * الحصول على التاريخ الهجري والمناسبة
 * @param offset إزاحة الأيام لمطابقة رؤية هلال النجف (السيستاني)
 */
export const getHijriDate = (offset: number = -1) => {
    const date = new Date();
    date.setDate(date.getDate() + offset);

    // استخدام islamic-civil لضمان ثبات الحسابات البرمجية
    const formatter = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-civil', {
        day: 'numeric',
        month: 'numeric',
        year: 'numeric'
    });

    const parts = formatter.formatToParts(date);

    // استخراج القيم بصيغة أرقام فقط
    const day = parseInt(parts.find(p => p.type === 'day')?.value || '0');
    const month = parseInt(parts.find(p => p.type === 'month')?.value || '0');
    // تنظيف السنة من أي أحرف إنجليزية قد يضيفها المتصفح
    const yearRaw = parts.find(p => p.type === 'year')?.value || '0';
    const year = yearRaw.replace(/[^\d]/g, ''); // إبقاء الأرقام فقط

    const monthNames = [
        "محرم الحرام", "صفر الخير", "ربيع الأول", "ربيع الثاني",
        "جمادى الأولى", "جمادى الآخرة", "رجب الأصب", "شعبان المعظم",
        "رمضان المبارك", "شوال المكرم", "ذو القعدة", "ذو الحجة"
    ];

    const monthName = monthNames[month - 1];

    // البحث عن مناسبة اليوم
    const occasion = occasions.find(o => o.day === day && o.month === month);

    // بناء التاريخ الكامل بشكل يدوي تماماً لمنع التداخل الإنجليزي
    const fullDate = `${day} ${monthName} ${year}`;

    return {
        day,
        month,
        monthName,
        year,
        fullDate,
        occasion
    };
};

