                                                    <img src={file.content} alt="upload" className="w-full h-full object-cover" />
                                                ) : (
                                                    <div className="w-full h-full flex flex-col items-center justify-center p-2 text-center">
                                                        <ClipboardDocumentListIcon className="w-6 h-6 text-gray-400" />
                                                        <span className="text-[8px] mt-1 text-gray-500 truncate w-full">{file.name}</span>
                                                    </div>
                                                )}
                                                <button type="button" onClick={() => setReportForm(p => ({...p, attachments: p.attachments.filter((_, i) => i !== idx)}))} className="absolute top-1 left-1 p-1 bg-red-500 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-all"><XMarkIcon className="w-3 h-3"/></button>
                                            </div>
                                        ))}
                                        <button 
                                            type="button" 
                                            onClick={() => fileInputRef.current?.click()}
                                            className="aspect-square bg-gray-50 dark:bg-gray-800 border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-2xl flex flex-col items-center justify-center gap-2 text-gray-400 hover:border-brand-light hover:text-brand-light transition-all active:scale-95"
                                        >
                                            <CameraIcon className="w-8 h-8" />
                                            <span className="text-[10px] font-bold">إضافة مرفق</span>
                                        </button>
                                        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,application/pdf" />
                                    </div>
                                </div>

                                <button type="submit" disabled={isSubmitting} className="w-full py-5 bg-brand-light text-white rounded-3xl font-bold text-lg shadow-xl shadow-brand-light/20 active:scale-95 disabled:opacity-50 transition-all flex items-center justify-center gap-3">
                                    {isSubmitting ? (
                                        <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                    ) : (
                                        <>
                                            <SparklesIcon className="w-6 h-6 text-brand-accent-yellow" />
                                            <span>إرسال التقرير النهائي</span>
                                        </>
                                    )}
                                </button>
                            </form>
                        )}

                        {activeTab === 'profile' && <ProfileManagement user={currentUser!} />}

                        {/* Footer Rights Info */}
                        <div className="mt-20 border-t dark:border-gray-800 pt-8 pb-4 text-center">
                            <div className="flex flex-col items-center gap-3 opacity-40 hover:opacity-100 transition-opacity">
                                <AppLogoIcon className="w-10 h-10 grayscale" />
                                <div className="space-y-1">
                                    <p className="text-xs font-bold text-gray-500 dark:text-gray-400">نظام التقارير اليومية الداخلي</p>
                                    <p className="text-[10px] text-gray-400">© 2025 جميع الحقوق محفوظة لشعبة الفنون والمسرح</p>
                                    <p className="text-[9px] font-bold text-brand-light">تطوير: حسين كاظم</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </main>
            </div>

            {selectedReport && <ReportDetailModal report={selectedReport} user={currentUser!} viewerRole={Role.EMPLOYEE} onClose={() => setSelectedReport(null)} />}
            {notification && <Toast message={notification.message} onClose={clearNotification} onClick={clearNotification} type={notification.type} />}
            {showLogoutConfirm && <ConfirmModal title="تسجيل الخروج" message="هل أنت متأكد من رغبتك في مغادرة النظام؟" onConfirm={logout} onCancel={() => setShowLogoutConfirm(false)} />}
            {showSubmitConfirm && <ConfirmModal title="تأكيد إرسال التقرير" message="سيتم إرسال كافة البيانات المكتوبة والمرفقات إلى المسؤول مباشرة. هل تود الاستمرار؟" onConfirm={handleFinalSubmit} onCancel={() => setShowSubmitConfirm(false)} confirmText="تأكيد وإرسال" />}
        </div>
    );
};

