            "دقتك في كتابة التقرير تعكس جودة عملك الميداني.",
            "كل مهمة تنجزها تقربنا خطوة إضافية نحو أهدافنا.",
            "الإبداع يبدأ بالالتزام، والتميز ينتهي بالإتقان."
        ];
        return quotes[Math.floor(Math.random() * quotes.length)];
    }, []);

    const myReports = useMemo(() => 
        reports.filter(r => r.userId === currentUser?.id && r.status === 'submitted')
               .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    , [reports, currentUser]);

    const unreadTasksCount = useMemo(() => 
        directTasks.filter(t => t.employeeId === currentUser?.id && t.status === 'pending' && !t.isReadByEmployee).length
    , [directTasks, currentUser]);

    // Explicitly typing the 'file' parameter to resolve 'unknown' type errors and ensure compatibility with FileReader and Blob properties.
    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;

        Array.from(files).forEach((file: File) => {
            const reader = new FileReader();
            reader.onloadend = () => {
                setReportForm(prev => ({
                    ...prev,
                    attachments: [...prev.attachments, {
                        name: file.name,
                        type: file.type,
                        size: file.size,
                        content: reader.result as string
                    }]
                }));
            };
            reader.readAsDataURL(file);
        });
    };

    const handleFinalSubmit = async () => {
        setIsSubmitting(true);
        setShowSubmitConfirm(false);
        try {
            await addReport({
                userId: currentUser!.id,
                date: new Date().toISOString().split('T')[0],
                day: new Intl.DateTimeFormat('ar-EG', { weekday: 'long' }).format(new Date()),
                tasks: reportForm.tasks.filter(t => t.text.trim()),
                accomplished: reportForm.accomplished,
                notAccomplished: reportForm.notAccomplished,
                attachments: reportForm.attachments
            });
            setReportForm({ tasks: [{ id: Date.now().toString(), text: '' }], accomplished: '', notAccomplished: '', attachments: [] });
            setActiveTab('archive');
        } catch (e) {} finally { setIsSubmitting(false); }
    };

    const NavItem = ({ tab, label, icon, count }: any) => (
        <button
            onClick={() => { setActiveTab(tab); setIsSidebarOpen(false); }}
            className={`flex items-center w-full px-4 py-3 text-sm font-medium transition-all rounded-xl ${activeTab === tab ? 'bg-brand-light text-white shadow-lg' : 'text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700/50'}`}
        >
            <div className="w-6 h-6">{icon}</div>
            <span className="mr-3">{label}</span>
            {count > 0 && <span className="mr-auto bg-brand-accent-red text-white text-[10px] font-bold px-2 py-0.5 rounded-full animate-pulse">{count}</span>}
        </button>
    );

    return (
        <div className="h-[100dvh] w-full bg-[#fcfdfe] dark:bg-[#0d1117] flex overflow-hidden">
            {isSidebarOpen && <div className="fixed inset-0 z-30 bg-black/60 backdrop-blur-sm md:hidden" onClick={() => setIsSidebarOpen(false)}></div>}

            <aside className={`fixed inset-y-0 right-0 z-40 w-72 h-full bg-white dark:bg-gray-900 shadow-2xl transform transition-transform duration-300 md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                <div className="flex flex-col h-full border-l dark:border-gray-800">
                    <div className="p-6 border-b dark:border-gray-800 flex flex-col items-center gap-2">
                        <AppLogoIcon className="w-12 h-12" />
                        <h1 className="text-lg font-bold dark:text-gray-100">مهامي اليومية</h1>
                        <button onClick={refreshData} className="p-1 text-brand-light hover:rotate-180 transition-transform duration-500">
                            <ArrowPathIcon className={`w-5 h-5 ${isSyncing ? 'animate-spin' : ''}`} />
                        </button>
                    </div>

                    <nav className="flex-grow px-4 py-6 space-y-2 overflow-y-auto no-scrollbar">
                        <NavItem tab="home" label="الرئيسية" icon={<HomeIcon />} />
                        <NavItem tab="new-report" label="إرسال تقرير" icon={<NewReportIcon />} />
                        <NavItem tab="tasks" label="المهام الواردة" icon={<InboxIcon />} count={unreadTasksCount} />
                        <NavItem tab="archive" label="الأرشيف" icon={<ArchiveBoxIcon />} />
                        <NavItem tab="profile" label="الملف الشخصي" icon={<UserCircleIcon />} />
                    </nav>

                    <div className="p-4 border-t dark:border-gray-800 space-y-2">
                        <ThemeToggle />
                        <button onClick={() => setShowLogoutConfirm(true)} className="flex items-center w-full px-4 py-3 text-sm font-bold text-red-500 rounded-xl hover:bg-red-50">
                            <LogoutIcon className="w-6 h-6"/>
                            <span className="mr-3">خروج</span>
                        </button>
                        <div className="pt-2 text-[10px] text-center text-gray-400 dark:text-gray-600 font-medium">
                            <p>© 2025 جميع الحقوق محفوظة</p>
                            <p>تطوير حسين كاظم</p>
                        </div>
                    </div>
                </div>
            </aside>

            <div className="flex-1 flex flex-col h-full overflow-hidden">
                {/* Mobile Header */}
                <header className="flex items-center justify-between p-4 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md border-b dark:border-gray-800 md:hidden z-20 sticky top-0">
                    <div className="flex items-center gap-2">
                        <AppLogoIcon className="w-8 h-8" />
                        <h2 className="text-lg font-bold dark:text-gray-100">مهامي</h2>
                    </div>
                    <div className="flex items-center gap-3">
                         {unreadTasksCount > 0 && <span className="w-2.5 h-2.5 bg-red-500 rounded-full animate-ping"></span>}
                         <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-gray-50 dark:bg-gray-800 rounded-2xl transition-all active:scale-90"><MenuIcon className="w-6 h-6" /></button>
                    </div>
                </header>

                <main className="flex-1 overflow-y-auto p-4 md:p-10 no-scrollbar">
                    <div className="container mx-auto max-w-4xl pb-10">
                        {/* 1. الصفحة الرئيسية: الترحيب والتحفيز */}
                        {activeTab === 'home' && (
                            <div className="space-y-6 animate-fade-in">
                                <div className="bg-gradient-to-br from-brand-dark to-brand-light p-8 rounded-[2.5rem] shadow-2xl text-white relative overflow-hidden">
                                    <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
                                        <div className="text-center md:text-right">
                                            <p className="text-brand-accent-yellow font-bold text-sm mb-1">{todayDate}</p>
                                            <h3 className="text-3xl font-bold">أهلاً بك، {currentUser?.fullName.split(' ')[0]} 👋</h3>
                                            <p className="mt-3 text-sm opacity-90 max-w-sm leading-relaxed italic">"{motivationalQuote}"</p>
                                        </div>
                                        <div className="bg-white/10 backdrop-blur-md p-4 rounded-3xl border border-white/20 text-center min-w-[140px]">
                                            <p className="text-[10px] font-bold uppercase tracking-wider opacity-70">المهام الجديدة</p>
                                            <p className="text-4xl font-black mt-1">{unreadTasksCount}</p>
                                        </div>
                                    </div>
                                    <div className="absolute -bottom-10 -left-10 w-40 h-40 bg-white/5 rounded-full blur-2xl"></div>
                                    <div className="absolute -top-10 right-0 w-32 h-32 bg-brand-accent-yellow/10 rounded-full blur-2xl"></div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                    <button onClick={() => setActiveTab('new-report')} className="p-6 bg-white dark:bg-gray-800 rounded-3xl shadow-sm border dark:border-gray-700 flex flex-col items-center gap-3 transition-all hover:shadow-md active:scale-95 group">
                                        <div className="p-4 bg-brand-light/10 text-brand-light rounded-2xl group-hover:bg-brand-light group-hover:text-white transition-all"><NewReportIcon className="w-8 h-8" /></div>
                                        <span className="font-bold text-gray-700 dark:text-gray-200">إرسال تقرير جديد</span>
                                    </button>
                                    <button onClick={() => setActiveTab('tasks')} className="p-6 bg-white dark:bg-gray-800 rounded-3xl shadow-sm border dark:border-gray-700 flex flex-col items-center gap-3 transition-all hover:shadow-md active:scale-95 group">
                                        <div className="p-4 bg-brand-accent-green/10 text-brand-accent-green rounded-2xl group-hover:bg-brand-accent-green group-hover:text-white transition-all"><InboxIcon className="w-8 h-8" /></div>
                                        <span className="font-bold text-gray-700 dark:text-gray-200">المهام الواردة</span>
                                    </button>
                                    <button onClick={() => setActiveTab('archive')} className="p-6 bg-white dark:bg-gray-800 rounded-3xl shadow-sm border dark:border-gray-700 flex flex-col items-center gap-3 transition-all hover:shadow-md active:scale-95 group">
                                        <div className="p-4 bg-brand-dark/10 text-brand-dark rounded-2xl group-hover:bg-brand-dark group-hover:text-white transition-all"><ArchiveBoxIcon className="w-8 h-8" /></div>
                                        <span className="font-bold text-gray-700 dark:text-gray-200">أرشيف التقارير</span>
                                    </button>
                                </div>
                            </div>
                        )}

                        {/* 2. المهام الواردة */}
                        {activeTab === 'tasks' && <DirectTasksView />}

                        {/* 3. الأرشيف */}
                        {activeTab === 'archive' && (
                            <div className="space-y-4 animate-fade-in">
                                <div className="flex items-center justify-between mb-2 px-2">
                                    <h3 className="font-bold text-lg dark:text-white">سجل التقارير</h3>
                                    <span className="text-xs text-gray-500 font-bold">{myReports.length} تقرير</span>
                                </div>
                                {myReports.map(r => (
                                    <ReportView key={r.id} report={r} user={currentUser!} viewerRole={Role.EMPLOYEE} onClick={() => setSelectedReport(r)} />
                                ))}
                                {myReports.length === 0 && (
                                    <div className="text-center p-20 bg-gray-50 dark:bg-gray-800/50 rounded-3xl border-2 border-dashed border-gray-200 dark:border-gray-700">
                                        <p className="text-gray-400">لا يوجد تقارير في الأرشيف حالياً.</p>
                                    </div>
                                )}
                            </div>
                        )}

                        {/* 4. إرسال تقرير (النموذج الكامل) */}
                        {activeTab === 'new-report' && (
                            <form onSubmit={(e) => { e.preventDefault(); setShowSubmitConfirm(true); }} className="bg-white dark:bg-gray-800 p-6 md:p-8 rounded-[2.5rem] shadow-sm border dark:border-gray-700 space-y-8 animate-fade-in">
                                <div className="border-b dark:border-gray-700 pb-4 flex justify-between items-center">
                                    <div>
                                        <h3 className="text-xl font-bold dark:text-white">نموذج تقرير العمل</h3>
                                        <p className="text-xs text-gray-400 mt-1">يرجى ملء الحقول بدقة لضمان صحة التقييم.</p>
                                    </div>
                                    <div className="text-left">
                                        <p className="text-xs font-bold text-brand-light">{todayDate.split(',')[0]}</p>
                                        <p className="text-[10px] text-gray-400">{new Date().toLocaleDateString('en-GB')}</p>
                                    </div>
                                </div>

                                {/* حقل المهام المتعددة */}
                                <div className="space-y-4">
                                    <label className="block text-sm font-bold text-brand-dark dark:text-brand-light">قائمة المهام اليومية:</label>
                                    {reportForm.tasks.map((task, idx) => (
                                        <div key={task.id} className="flex gap-3 animate-fade-in">
                                            <div className="flex-shrink-0 w-8 h-8 rounded-full bg-gray-100 dark:bg-gray-700 flex items-center justify-center text-xs font-bold text-gray-400">{idx + 1}</div>
                                            <textarea 
                                                value={task.text} 
                                                onChange={(e) => setReportForm(p => ({ ...p, tasks: p.tasks.map(t => t.id === task.id ? { ...t, text: e.target.value } : t) }))} 
                                                placeholder={`اكتب المهمة هنا...`} 
                                                className="flex-1 px-4 py-3 border dark:border-gray-700 rounded-2xl bg-gray-50 dark:bg-gray-700 dark:text-white outline-none focus:ring-2 focus:ring-brand-light/50 transition-all min-h-[50px] resize-none" 
                                            />
                                            {idx > 0 && (
                                                <button type="button" onClick={() => setReportForm(p => ({...p, tasks: p.tasks.filter(t => t.id !== task.id)}))} className="p-3 text-red-500 hover:bg-red-50 rounded-xl transition-all"><TrashIcon className="w-5 h-5"/></button>
                                            )}
                                        </div>
                                    ))}
                                    <button type="button" onClick={() => setReportForm(p => ({...p, tasks: [...p.tasks, {id: Date.now().toString(), text: ''}]}))} className="text-xs font-bold text-brand-light flex items-center gap-2 px-4 py-2 bg-brand-light/10 rounded-xl hover:bg-brand-light/20 transition-all"><PlusIcon className="w-4 h-4"/> إضافة حقل مهمة آخر</button>
                                </div>

                                <div className="space-y-6">
                                    <div>
                                        <label className="block text-sm font-bold text-brand-dark dark:text-brand-light mb-2">خلاصة المنجز وما تم تحقيقه:</label>
                                        <textarea placeholder="اكتب خلاصة الإنجاز اليومي..." value={reportForm.accomplished} onChange={e => setReportForm(p => ({...p, accomplished: e.target.value}))} className="w-full p-4 border dark:border-gray-700 rounded-2xl bg-gray-50 dark:bg-gray-700 dark:text-white outline-none focus:ring-2 focus:ring-brand-light/50" rows={3} />
                                    </div>
                                    <div>
                                        <label className="block text-sm font-bold text-brand-dark dark:text-brand-light mb-2">المعوقات أو المهام غير المنجزة (إن وجدت):</label>
                                        <textarea placeholder="اذكر أي معوقات واجهتك..." value={reportForm.notAccomplished} onChange={e => setReportForm(p => ({...p, notAccomplished: e.target.value}))} className="w-full p-4 border dark:border-gray-700 rounded-2xl bg-gray-50 dark:bg-gray-700 dark:text-white outline-none focus:ring-2 focus:ring-brand-light/50" rows={3} />
                                    </div>
                                </div>

                                {/* قسم المرفقات */}
                                <div className="space-y-4">
                                    <label className="block text-sm font-bold text-brand-dark dark:text-brand-light">المرفقات والوثائق المصاحبة:</label>
                                    <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
                                        {reportForm.attachments.map((file, idx) => (
                                            <div key={idx} className="relative aspect-square bg-gray-100 dark:bg-gray-700 rounded-2xl overflow-hidden border dark:border-gray-600 group">
                                                {file.type.startsWith('image/') ? (
                                                    <img src={file.content} alt="upload" className="w-full h-full object-cover" />
                                                ) : (
                                                    <div className="w-full h-full flex flex-col items-center justify-center p-2 text-center">
                                                        <ClipboardDocumentListIcon className="w-6 h-6 text-gray-400" />
                                                        <span className="text-[8px] mt-1 text-gray-500 truncate w-full">{file.name}</span>
                                                    </div>
                                                )}
                                                <button type="button" onClick={() => setReportForm(p => ({...p, attachments: p.attachments.filter((_, i) => i !== idx)}))} className="absolute top-1 left-1 p-1 bg-red-500 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-all"><XMarkIcon className="w-3 h-3"/></button>
                                            </div>
                                        ))}
                                        <button 
                                            type="button" 
                                            onClick={() => fileInputRef.current?.click()}
                                            className="aspect-square bg-gray-50 dark:bg-gray-800 border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-2xl flex flex-col items-center justify-center gap-2 text-gray-400 hover:border-brand-light hover:text-brand-light transition-all active:scale-95"
                                        >
                                            <CameraIcon className="w-8 h-8" />
                                            <span className="text-[10px] font-bold">إضافة مرفق</span>
                                        </button>
                                        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*,application/pdf" />
                                    </div>
                                </div>

                                <button type="submit" disabled={isSubmitting} className="w-full py-5 bg-brand-light text-white rounded-3xl font-bold text-lg shadow-xl shadow-brand-light/20 active:scale-95 disabled:opacity-50 transition-all flex items-center justify-center gap-3">
                                    {isSubmitting ? (
                                        <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                    ) : (
                                        <>
                                            <SparklesIcon className="w-6 h-6 text-brand-accent-yellow" />
                                            <span>إرسال التقرير النهائي</span>
                                        </>
                                    )}
                                </button>
                            </form>
                        )}

                        {activeTab === 'profile' && <ProfileManagement user={currentUser!} />}

                        {/* Footer Rights Info */}
                        <div className="mt-20 border-t dark:border-gray-800 pt-8 pb-4 text-center">
                            <div className="flex flex-col items-center gap-3 opacity-40 hover:opacity-100 transition-opacity">
                                <AppLogoIcon className="w-10 h-10 grayscale" />
                                <div className="space-y-1">
                                    <p className="text-xs font-bold text-gray-500 dark:text-gray-400">نظام التقارير اليومية الداخلي</p>
                                    <p className="text-[10px] text-gray-400">© 2025 جميع الحقوق محفوظة لشعبة الفنون والمسرح</p>
                                    <p className="text-[9px] font-bold text-brand-light">تطوير: حسين كاظم</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </main>
            </div>

            {selectedReport && <ReportDetailModal report={selectedReport} user={currentUser!} viewerRole={Role.EMPLOYEE} onClose={() => setSelectedReport(null)} />}
            {notification && <Toast message={notification.message} onClose={clearNotification} onClick={clearNotification} type={notification.type} />}
            {showLogoutConfirm && <ConfirmModal title="تسجيل الخروج" message="هل أنت متأكد من رغبتك في مغادرة النظام؟" onConfirm={logout} onCancel={() => setShowLogoutConfirm(false)} />}
            {showSubmitConfirm && <ConfirmModal title="تأكيد إرسال التقرير" message="سيتم إرسال كافة البيانات المكتوبة والمرفقات إلى المسؤول مباشرة. هل تود الاستمرار؟" onConfirm={handleFinalSubmit} onCancel={() => setShowSubmitConfirm(false)} confirmText="تأكيد وإرسال" />}
        </div>
    );
};

export default EmployeeDashboard;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useData } from '../context/DataContext';
import { Role, Attachment, Report } from '../types';
import LogoutIcon from './icons/LogoutIcon';
import ReportView from './ReportView';
import NewReportIcon from './icons/NewReportIcon';
import InboxIcon from './icons/InboxIcon';
import ProfileManagement from './ProfileManagement';
import UserCircleIcon from './icons/UserCircleIcon';
import ReportDetailModal from './ReportDetailModal';
import Toast from './Toast';
import MenuIcon from './icons/MenuIcon';
import ThemeToggle from './ThemeToggle';
import AppLogoIcon from './icons/AppLogoIcon';
import HomeIcon from './icons/HomeIcon';
import DirectTasksView from './DirectTasksView';
import ArchiveBoxIcon from './icons/ArchiveBoxIcon';
import ClipboardDocumentListIcon from './icons/ClipboardDocumentListIcon';
import ArrowPathIcon from './icons/ArrowPathIcon';
import SparklesIcon from './icons/SparklesIcon';
import PlusIcon from './icons/PlusIcon';
import TrashIcon from './icons/TrashIcon';
import CameraIcon from './icons/CameraIcon';
import XMarkIcon from './icons/XMarkIcon';
import ConfirmModal from './ConfirmModal';

const EmployeeDashboard: React.FC = () => {
    const { currentUser, logout } = useAuth();
    const { reports, directTasks, addReport, notification, clearNotification, isSyncing, refreshData } = useData();

    const [activeTab, setActiveTab] = useState('home');
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const [selectedReport, setSelectedReport] = useState<Report | null>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
    const [showSubmitConfirm, setShowSubmitConfirm] = useState(false);

    const [reportForm, setReportForm] = useState({
        tasks: [{ id: Date.now().toString(), text: '' }],
        accomplished: '',
        notAccomplished: '',
        attachments: [] as Attachment[]
    });

    const fileInputRef = useRef<HTMLInputElement>(null);

    const todayDate = useMemo(() => {
        return new Intl.DateTimeFormat('ar-EG', { 
            weekday: 'long', 
            day: 'numeric', 
            month: 'long'
        }).format(new Date());
    }, []);

    const fullYear = new Date().getFullYear();

    const motivationalQuote = useMemo(() => {
        const quotes = [
            "إنجازك اليوم يبني نجاح الغد.",
            "دقتك تعكس مهنيتك العالية.",
            "نقدر جهودك المتميزة دائماً.",
            "الإبداع يبدأ بالالتزام والإتقان."
        ];
        return quotes[Math.floor(Math.random() * quotes.length)];
    }, []);

    const myReports = useMemo(() => 
        reports.filter(r => r.userId === currentUser?.id && r.status === 'submitted')
               .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    , [reports, currentUser]);

    const unreadTasksCount = useMemo(() => 
        directTasks.filter(t => t.employeeId === currentUser?.id && t.status === 'pending' && !t.isReadByEmployee).length
    , [directTasks, currentUser]);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;

        Array.from(files).forEach((file: File) => {
            const reader = new FileReader();
            reader.onloadend = () => {
                setReportForm(prev => ({
                    ...prev,
                    attachments: [...prev.attachments, {
                        name: file.name,
                        type: file.type,
                        size: file.size,
                        content: reader.result as string
                    }]
                }));
            };
            reader.readAsDataURL(file);
        });
    };

    const handleFinalSubmit = async () => {
        setIsSubmitting(true);
        setShowSubmitConfirm(false);
        try {
            await addReport({
                userId: currentUser!.id,
                date: new Date().toISOString().split('T')[0],
                day: new Intl.DateTimeFormat('ar-EG', { weekday: 'long' }).format(new Date()),
                tasks: reportForm.tasks.filter(t => t.text.trim()),
                accomplished: reportForm.accomplished,
                notAccomplished: reportForm.notAccomplished,
                attachments: reportForm.attachments
            });
            setReportForm({ tasks: [{ id: Date.now().toString(), text: '' }], accomplished: '', notAccomplished: '', attachments: [] });
            setActiveTab('archive');
        } catch (e) {} finally { setIsSubmitting(false); }
    };

    const NavItem = ({ tab, label, icon, count }: any) => (
        <button
            onClick={() => { setActiveTab(tab); setIsSidebarOpen(false); }}
            className={`flex items-center w-full px-4 py-2.5 text-sm font-medium transition-all rounded-xl ${activeTab === tab ? 'bg-brand-light text-white shadow-md' : 'text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700/50'}`}
        >
            <div className="w-5 h-5">{icon}</div>
            <span className="mr-3">{label}</span>
            {count > 0 && <span className="mr-auto bg-brand-accent-red text-white text-[10px] font-bold px-2 py-0.5 rounded-full">{count}</span>}
        </button>
    );

    return (
        <div className="h-[100dvh] w-full bg-[#f8f9fc] dark:bg-[#0d1117] flex overflow-hidden">
            {isSidebarOpen && <div className="fixed inset-0 z-30 bg-black/40 backdrop-blur-sm md:hidden" onClick={() => setIsSidebarOpen(false)}></div>}

            <aside className={`fixed inset-y-0 right-0 z-40 w-64 h-full bg-white dark:bg-gray-900 shadow-2xl transform transition-transform duration-300 md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                <div className="flex flex-col h-full border-l dark:border-gray-800">
                    <div className="p-5 border-b dark:border-gray-800 flex flex-col items-center gap-1">
                        <AppLogoIcon className="w-10 h-10" />
                        <h1 className="text-sm font-bold dark:text-gray-100">مهامي اليومية</h1>
                        <button onClick={refreshData} className="mt-1 p-1 text-brand-light/60 hover:text-brand-light transition-colors">
                            <ArrowPathIcon className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                        </button>
                    </div>

                    <nav className="flex-grow px-3 py-4 space-y-1 overflow-y-auto no-scrollbar">
                        <NavItem tab="home" label="الرئيسية" icon={<HomeIcon />} />
                        <NavItem tab="new-report" label="إرسال تقرير" icon={<NewReportIcon />} />
                        <NavItem tab="tasks" label="المهام الواردة" icon={<InboxIcon />} count={unreadTasksCount} />
                        <NavItem tab="archive" label="الأرشيف" icon={<ArchiveBoxIcon />} />
                        <NavItem tab="profile" label="الملف الشخصي" icon={<UserCircleIcon />} />
                    </nav>

                    <div className="p-3 border-t dark:border-gray-800 space-y-1">
                        <ThemeToggle />
                        <button onClick={() => setShowLogoutConfirm(true)} className="flex items-center w-full px-4 py-2 text-xs font-bold text-red-500 rounded-xl hover:bg-red-50">
                            <LogoutIcon className="w-5 h-5"/>
                            <span className="mr-3">خروج</span>
                        </button>
                        <div className="pt-2 text-[9px] text-center text-gray-400">
                            <p>© {fullYear} جميع الحقوق محفوظة</p>
                            <p className="font-bold text-brand-light">تصميم حسين كاظم</p>
                        </div>
                    </div>
                </div>
            </aside>

            <div className="flex-1 flex flex-col h-full overflow-hidden">
                <header className="flex items-center justify-between p-3 bg-white/80 dark:bg-gray-900/80 backdrop-blur-md border-b dark:border-gray-800 md:hidden z-20">
                    <div className="flex items-center gap-2">
                        <AppLogoIcon className="w-7 h-7" />
                        <h2 className="text-sm font-bold dark:text-gray-100">مهامي</h2>
                    </div>
                    <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-gray-50 dark:bg-gray-800 rounded-xl"><MenuIcon className="w-5 h-5" /></button>
                </header>

                <main className="flex-1 overflow-y-auto p-3 md:p-8 no-scrollbar">
                    <div className="container mx-auto max-w-3xl pb-6">
                        {activeTab === 'home' && (
                            <div className="space-y-4 animate-fade-in">
                                <div className="bg-gradient-to-br from-brand-dark to-brand-light p-5 rounded-3xl shadow-lg text-white relative overflow-hidden">
                                    <div className="relative z-10 flex items-center justify-between">
                                        <div className="text-right">
                                            <p className="text-[10px] text-brand-accent-yellow font-bold uppercase">{todayDate}</p>
                                            <h3 className="text-xl font-bold mt-0.5">أهلاً، {currentUser?.fullName.split(' ')[0]} 👋</h3>
                                            <p className="mt-1 text-[11px] opacity-80 leading-relaxed max-w-[200px]">"{motivationalQuote}"</p>
                                        </div>
                                        <div className="bg-white/10 backdrop-blur-md px-3 py-2 rounded-2xl border border-white/20 text-center min-w-[80px]">
                                            <p className="text-[8px] font-bold uppercase opacity-70">مهام جديدة</p>
                                            <p className="text-2xl font-black">{unreadTasksCount}</p>
                                        </div>
                                    </div>
                                    <SparklesIcon className="absolute -bottom-2 -left-2 w-12 h-12 text-white/5" />
                                </div>

                                <div className="grid grid-cols-2 gap-3">
                                    <button onClick={() => setActiveTab('new-report')} className="p-4 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700 flex flex-col items-center gap-2 transition-all active:scale-95">
                                        <div className="p-2.5 bg-brand-light/10 text-brand-light rounded-xl"><NewReportIcon className="w-5 h-5" /></div>
                                        <span className="text-xs font-bold text-gray-700 dark:text-gray-200">تقرير جديد</span>
                                    </button>
                                    <button onClick={() => setActiveTab('tasks')} className="p-4 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700 flex flex-col items-center gap-2 transition-all active:scale-95">
                                        <div className="p-2.5 bg-brand-accent-green/10 text-brand-accent-green rounded-xl"><InboxIcon className="w-5 h-5" /></div>
                                        <span className="text-xs font-bold text-gray-700 dark:text-gray-200">المهام الواردة</span>
                                    </button>
                                    <button onClick={() => setActiveTab('archive')} className="p-4 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700 flex flex-col items-center gap-2 transition-all active:scale-95">
                                        <div className="p-2.5 bg-brand-dark/10 text-brand-dark rounded-xl"><ArchiveBoxIcon className="w-5 h-5" /></div>
                                        <span className="text-xs font-bold text-gray-700 dark:text-gray-200">الأرشيف</span>
                                    </button>
                                    <button onClick={() => setActiveTab('profile')} className="p-4 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border dark:border-gray-700 flex flex-col items-center gap-2 transition-all active:scale-95">
                                        <div className="p-2.5 bg-brand-accent-yellow/10 text-brand-accent-yellow rounded-xl"><UserCircleIcon className="w-5 h-5" /></div>
                                        <span className="text-xs font-bold text-gray-700 dark:text-gray-200">الحساب</span>
                                    </button>
                                </div>
                            </div>
                        )}

                        {activeTab === 'tasks' && <DirectTasksView />}

                        {activeTab === 'archive' && (
                            <div className="space-y-3 animate-fade-in">
                                <div className="flex items-center justify-between px-1">
                                    <h3 className="font-bold text-sm dark:text-white">السجل اليومي</h3>
                                    <span className="text-[10px] text-gray-400">{myReports.length} تقارير</span>
                                </div>
                                {myReports.map(r => (
                                    <ReportView key={r.id} report={r} user={currentUser!} viewerRole={Role.EMPLOYEE} onClick={() => setSelectedReport(r)} />
                                ))}
                            </div>
                        )}

                        {activeTab === 'new-report' && (
                            <form onSubmit={(e) => { e.preventDefault(); setShowSubmitConfirm(true); }} className="bg-white dark:bg-gray-800 p-4 rounded-3xl shadow-sm border dark:border-gray-700 space-y-5 animate-fade-in">
                                <div className="flex justify-between items-center pb-2 border-b dark:border-gray-700">
                                    <h3 className="text-sm font-bold dark:text-white">كتابة تقرير اليوم</h3>
                                    <span className="text-[10px] text-gray-400">{new Date().toLocaleDateString('ar-EG')}</span>
                                </div>

                                <div className="space-y-3">
                                    <label className="block text-[11px] font-bold text-brand-dark dark:text-brand-light">قائمة المهام المنجزة:</label>
                                    {reportForm.tasks.map((task, idx) => (
                                        <div key={task.id} className="flex gap-2 animate-fade-in">
                                            <textarea 
                                                value={task.text} 
                                                onChange={(e) => setReportForm(p => ({ ...p, tasks: p.tasks.map(t => t.id === task.id ? { ...t, text: e.target.value } : t) }))} 
                                                placeholder={`المهمة ${idx + 1}...`} 
                                                className="flex-1 px-3 py-2 text-xs border dark:border-gray-700 rounded-xl bg-gray-50 dark:bg-gray-700 dark:text-white focus:ring-1 focus:ring-brand-light outline-none" 
                                                rows={1}
                                            />
                                            {idx > 0 && <button type="button" onClick={() => setReportForm(p => ({...p, tasks: p.tasks.filter(t => t.id !== task.id)}))} className="p-2 text-red-500"><TrashIcon className="w-4 h-4"/></button>}
                                        </div>
                                    ))}
                                    <button type="button" onClick={() => setReportForm(p => ({...p, tasks: [...p.tasks, {id: Date.now().toString(), text: ''}]}))} className="text-[10px] font-bold text-brand-light flex items-center gap-1 px-2 py-1 bg-brand-light/5 rounded-lg"><PlusIcon className="w-3 h-3"/> إضافة حقل</button>
                                </div>

                                <div className="space-y-4">
                                    <div>
                                        <label className="block text-[11px] font-bold text-brand-dark dark:text-brand-light mb-1.5">خلاصة المنجز:</label>
                                        <textarea placeholder="ماذا أنجزت اليوم باختصار؟" value={reportForm.accomplished} onChange={e => setReportForm(p => ({...p, accomplished: e.target.value}))} className="w-full p-3 text-xs border dark:border-gray-700 rounded-xl bg-gray-50 dark:bg-gray-700 dark:text-white" rows={2} />
                                    </div>
                                    <div>
                                        <label className="block text-[11px] font-bold text-brand-dark dark:text-brand-light mb-1.5">المعوقات (إن وجدت):</label>
                                        <textarea placeholder="أي تحديات واجهتك؟" value={reportForm.notAccomplished} onChange={e => setReportForm(p => ({...p, notAccomplished: e.target.value}))} className="w-full p-3 text-xs border dark:border-gray-700 rounded-xl bg-gray-50 dark:bg-gray-700 dark:text-white" rows={2} />
                                    </div>
                                </div>

                                <div>
                                    <label className="block text-[11px] font-bold text-brand-dark dark:text-brand-light mb-2">المرفقات والصور:</label>
                                    <div className="flex flex-wrap gap-2">
                                        {reportForm.attachments.map((file, idx) => (
                                            <div key={idx} className="relative w-12 h-12 bg-gray-100 rounded-lg overflow-hidden border">
                                                <img src={file.content} className="w-full h-full object-cover" />
                                                <button type="button" onClick={() => setReportForm(p => ({...p, attachments: p.attachments.filter((_, i) => i !== idx)}))} className="absolute top-0 right-0 p-0.5 bg-red-500 text-white"><XMarkIcon className="w-2 h-2"/></button>
                                            </div>
                                        ))}
                                        <button type="button" onClick={() => fileInputRef.current?.click()} className="w-12 h-12 border-2 border-dashed border-gray-200 rounded-lg flex items-center justify-center text-gray-400 hover:text-brand-light"><CameraIcon className="w-5 h-5" /></button>
                                        <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" multiple accept="image/*" />
                                    </div>
                                </div>

                                <button type="submit" disabled={isSubmitting} className="w-full py-3.5 bg-brand-light text-white rounded-2xl font-bold text-sm shadow-lg active:scale-95 disabled:opacity-50">إرسال التقرير النهائي</button>
                            </form>
                        )}

                        {activeTab === 'profile' && <ProfileManagement user={currentUser!} />}
                    </div>
                </main>
            </div>

            {selectedReport && <ReportDetailModal report={selectedReport} user={currentUser!} viewerRole={Role.EMPLOYEE} onClose={() => setSelectedReport(null)} />}
            {notification && <Toast message={notification.message} onClose={clearNotification} onClick={clearNotification} type={notification.type} />}
            {showLogoutConfirm && <ConfirmModal title="خروج" message="هل تود المغادرة؟" onConfirm={logout} onCancel={() => setShowLogoutConfirm(false)} />}
            {showSubmitConfirm && <ConfirmModal title="تأكيد" message="سيتم إرسال التقرير للمسؤول، هل أنت متأكد؟" onConfirm={handleFinalSubmit} onCancel={() => setShowSubmitConfirm(false)} />}
        </div>
    );
};

export default EmployeeDashboard;

import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useData } from '../context/DataContext';
import LockIcon from './icons/LockIcon';
import AppLogoIcon from './icons/AppLogoIcon';
import UserIcon from './icons/UserIcon';
import EyeIcon from './icons/EyeIcon';
import EyeSlashIcon from './icons/EyeSlashIcon';

const Login: React.FC = () => {
    const { login, loginLoading } = useAuth();
    const { unlockAudio } = useData();

    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [rememberMe, setRememberMe] = useState(false);
    const [error, setError] = useState('');

    const handleLoginSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');
        unlockAudio();

        if (!username || !password) {
            setError('الرجاء إدخال اسم المستخدم وكلمة المرور.');
            return;
        }
        const success = await login(username, password, rememberMe);
        if (!success) {
            setError('اسم المستخدم أو كلمة المرور غير صحيحة.');
        }
    };

    return (
        <div className="flex items-center justify-center min-h-screen bg-[#f0f4f8] dark:bg-gray-950 relative overflow-hidden font-['Cairo']">
            {/* الدوائر الزخرفية الخلفية - لمسة احترافية */}
            <div className="absolute top-[-10%] left-[-5%] w-[40%] h-[40%] bg-brand-light/10 rounded-full blur-[100px]"></div>
            <div className="absolute bottom-[-10%] right-[-5%] w-[40%] h-[40%] bg-brand-dark/10 rounded-full blur-[100px]"></div>

            <div className="w-full max-w-md p-2 z-10">
                <div className="bg-white/80 dark:bg-gray-900/80 backdrop-blur-xl p-10 rounded-[2.5rem] shadow-[0_20px_50px_rgba(0,0,0,0.05)] dark:shadow-[0_20px_50px_rgba(0,0,0,0.3)] border border-white dark:border-gray-800">
                    <div className="flex flex-col items-center text-center">
                        <div className="w-16 h-16 mb-6 drop-shadow-xl transition-transform hover:scale-105 duration-300">
                            <AppLogoIcon />
                        </div>
                        <h2 className="text-2xl font-black text-brand-dark dark:text-white">تسجيل الدخول</h2>
                        <p className="mt-2 text-xs text-gray-500 dark:text-gray-400 font-bold uppercase tracking-widest">نظام إدارة المهام اليومية</p>
                    </div>

                    <form className="mt-10 space-y-6" onSubmit={handleLoginSubmit}>
                        <div className="space-y-4">
                            <div className="group">
                                <label className="block text-[10px] font-black text-gray-400 mr-4 mb-1 uppercase tracking-tighter">اسم المستخدم</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 right-0 flex items-center pr-4 pointer-events-none group-focus-within:text-brand-light text-gray-400 transition-colors">
                                        <UserIcon className="w-5 h-5" />
                                    </div>
                                    <input 
                                        type="text" 
                                        value={username} 
                                        onChange={(e) => setUsername(e.target.value)} 
                                        className="w-full px-5 py-3.5 bg-gray-50 dark:bg-gray-800 border-none rounded-2xl pr-12 text-sm focus:ring-2 focus:ring-brand-light/20 outline-none transition-all dark:text-white" 
                                        placeholder="Username" 
                                    />
                                </div>
                            </div>

                            <div className="group">
                                <label className="block text-[10px] font-black text-gray-400 mr-4 mb-1 uppercase tracking-tighter">كلمة المرور</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 right-0 flex items-center pr-4 pointer-events-none group-focus-within:text-brand-light text-gray-400 transition-colors">
                                        <LockIcon className="w-5 h-5" />
                                    </div>
                                    <input 
                                        type={showPassword ? 'text' : 'password'} 
                                        value={password} 
                                        onChange={(e) => setPassword(e.target.value)} 
                                        className="w-full px-5 py-3.5 bg-gray-50 dark:bg-gray-800 border-none rounded-2xl pr-12 pl-12 text-sm focus:ring-2 focus:ring-brand-light/20 outline-none transition-all dark:text-white" 
                                        placeholder="••••••••" 
                                    />
                                    <button 
                                        type="button" 
                                        onClick={() => setShowPassword(!showPassword)} 
                                        className="absolute inset-y-0 left-0 flex items-center pl-4 text-gray-400 hover:text-brand-light transition-colors"
                                    >
                                        {showPassword ? <EyeSlashIcon className="w-5 h-5" /> : <EyeIcon className="w-5 h-5" />}
                                    </button>
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center mr-2">
                            <input
                                id="remember-me"
                                type="checkbox"
                                checked={rememberMe}
                                onChange={(e) => setRememberMe(e.target.checked)}
                                className="w-4 h-4 text-brand-light border-none rounded-lg bg-gray-100 dark:bg-gray-800 focus:ring-brand-light/30"
                            />
                            <label htmlFor="remember-me" className="mr-3 text-xs font-bold text-gray-500 cursor-pointer select-none">تذكر بيانات الدخول</label>
                        </div>

                        {error && (
                            <div className="p-3 bg-red-50 dark:bg-red-900/20 rounded-xl border border-red-100 dark:border-red-900/30">
                                <p className="text-[11px] text-red-600 dark:text-red-400 text-center font-bold">{error}</p>
                            </div>
                        )}

                        <button 
                            type="submit" 
                            disabled={loginLoading} 
                            className="w-full py-4 bg-brand-dark dark:bg-brand-light text-white rounded-2xl font-black text-sm shadow-xl shadow-brand-dark/20 hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50"
                        >
                            {loginLoading ? 'جارِ التحقق...' : 'دخول للنظام'}
                        </button>
                    </form>
                </div>

                <p className="mt-8 text-center text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                    تطوير حسين كاظم &copy; ٢٠٢٥
                </p>
            </div>
        </div>
    );
};

export default Login;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import { useData } from '../context/DataContext';
import { Role, Attachment, Report } from '../types';
import LogoutIcon from './icons/LogoutIcon';
import ReportView from './ReportView';
import NewReportIcon from './icons/NewReportIcon';
import InboxIcon from './icons/InboxIcon';
import ProfileManagement from './ProfileManagement';
import UserCircleIcon from './icons/UserCircleIcon';
import ReportDetailModal from './ReportDetailModal';
import Toast from './Toast';
import MenuIcon from './icons/MenuIcon';
import ThemeToggle from './ThemeToggle';
import AppLogoIcon from './icons/AppLogoIcon';
import HomeIcon from './icons/HomeIcon';
import DirectTasksView from './DirectTasksView';
import ArchiveBoxIcon from './icons/ArchiveBoxIcon';
import ClipboardDocumentListIcon from './icons/ClipboardDocumentListIcon';
import ArrowPathIcon from './icons/ArrowPathIcon';
import SparklesIcon from './icons/SparklesIcon';
import PlusIcon from './icons/PlusIcon';
import TrashIcon from './icons/TrashIcon';
import CameraIcon from './icons/CameraIcon';
import XMarkIcon from './icons/XMarkIcon';
import ConfirmModal from './ConfirmModal';

const EmployeeDashboard: React.FC = () => {
    const { currentUser, logout } = useAuth();
    const { reports, directTasks, addReport, notification, clearNotification, isSyncing, refreshData } = useData();

    const [activeTab, setActiveTab] = useState('home');
    const [isSidebarOpen, setIsSidebarOpen] = useState(false);
    const [selectedReport, setSelectedReport] = useState<Report | null>(null);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
    const [showSubmitConfirm, setShowSubmitConfirm] = useState(false);

    const [reportForm, setReportForm] = useState({
        tasks: [{ id: Date.now().toString(), text: '' }],
        accomplished: '',
        notAccomplished: '',
        attachments: [] as Attachment[]
    });

    const fileInputRef = useRef<HTMLInputElement>(null);

    const todayDate = useMemo(() => {
        return new Intl.DateTimeFormat('ar-EG', { 
            weekday: 'long', 
            day: 'numeric', 
            month: 'long'
        }).format(new Date());
    }, []);

    const fullYear = new Date().getFullYear();

    const motivationalQuote = useMemo(() => {
        const quotes = [
            "إنجازك اليوم يبني نجاح الغد.",
            "دقتك تعكس مهنيتك العالية.",
            "نقدر جهودك المتميزة دائماً.",
            "الإبداع يبدأ بالالتزام والإتقان."
        ];
        return quotes[Math.floor(Math.random() * quotes.length)];
    }, []);

    const myReports = useMemo(() => 
        reports.filter(r => r.userId === currentUser?.id && r.status === 'submitted')
               .sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime())
    , [reports, currentUser]);

    const unreadTasksCount = useMemo(() => 
        directTasks.filter(t => t.employeeId === currentUser?.id && t.status === 'pending' && !t.isReadByEmployee).length
    , [directTasks, currentUser]);

    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files;
        if (!files) return;

        Array.from(files).forEach((file: File) => {
            const reader = new FileReader();
            reader.onloadend = () => {
                setReportForm(prev => ({
                    ...prev,
                    attachments: [...prev.attachments, {
                        name: file.name,
                        type: file.type,
                        size: file.size,
                        content: reader.result as string
                    }]
                }));
            };
            reader.readAsDataURL(file);
        });
    };

    const handleFinalSubmit = async () => {
        setIsSubmitting(true);
        setShowSubmitConfirm(false);
        try {
            await addReport({
                userId: currentUser!.id,
                date: new Date().toISOString().split('T')[0],
                day: new Intl.DateTimeFormat('ar-EG', { weekday: 'long' }).format(new Date()),
                tasks: reportForm.tasks.filter(t => t.text.trim()),
                accomplished: reportForm.accomplished,
                notAccomplished: reportForm.notAccomplished,
                attachments: reportForm.attachments
            });
            setReportForm({ tasks: [{ id: Date.now().toString(), text: '' }], accomplished: '', notAccomplished: '', attachments: [] });
            setActiveTab('archive');
        } catch (e) {} finally { setIsSubmitting(false); }
    };

    const NavItem = ({ tab, label, icon, count }: any) => (
        <button
            onClick={() => { setActiveTab(tab); setIsSidebarOpen(false); }}
            className={`flex items-center w-full px-4 py-3 text-sm font-bold transition-all rounded-2xl mb-1 ${activeTab === tab ? 'bg-brand-light/10 text-brand-light dark:bg-brand-light/20' : 'text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800'}`}
        >
            <div className="w-5 h-5">{icon}</div>
            <span className="mr-3">{label}</span>
            {count > 0 && <span className="mr-auto bg-brand-accent-red text-white text-[10px] font-black px-2 py-0.5 rounded-full">{count}</span>}
        </button>
    );

    return (
        <div className="h-[100dvh] w-full bg-[#f4f7fa] dark:bg-[#0a0d11] flex overflow-hidden font-['Cairo']">
            {isSidebarOpen && <div className="fixed inset-0 z-30 bg-black/30 backdrop-blur-sm md:hidden" onClick={() => setIsSidebarOpen(false)}></div>}

            <aside className={`fixed inset-y-0 right-0 z-40 w-72 h-full bg-white dark:bg-gray-900 shadow-[20px_0_40px_rgba(0,0,0,0.02)] dark:shadow-none transform transition-transform duration-500 md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                <div className="flex flex-col h-full border-l dark:border-gray-800">
                    <div className="p-8 border-b dark:border-gray-800 flex flex-col items-center gap-2">
                        <AppLogoIcon className="w-12 h-12" />
                        <h1 className="text-sm font-black dark:text-white uppercase tracking-tighter">نظام مهامي</h1>
