                        <button onClick={() => setShowLogoutConfirm(true)} className="flex items-center w-full px-4 py-2 text-[11px] font-black text-red-400 uppercase hover:bg-red-50 dark:hover:bg-red-900/10 rounded-xl transition-all">
                            <LogoutIcon className="w-4 h-4 ml-3"/>
                            خروج من النظام
                        </button>
                    </div>
                </div>
            </aside>

            <div className="flex-1 flex flex-col h-full overflow-hidden">
                <header className="flex items-center justify-between p-5 bg-white/70 dark:bg-gray-900/70 backdrop-blur-xl border-b dark:border-gray-800 md:hidden z-20">
                    <div className="flex items-center gap-3">
                        <AppLogoIcon className="w-8 h-8" />
                        <h2 className="text-sm font-black dark:text-white">مهامي اليومية</h2>
                    </div>
                    <button onClick={() => setIsSidebarOpen(true)} className="p-3 bg-gray-100 dark:bg-gray-800 rounded-2xl text-gray-600 dark:text-gray-300 active:scale-90 transition-transform">
                        <MenuIcon className="w-5 h-5" />
                    </button>
                </header>

                <main className="flex-1 overflow-y-auto p-4 md:p-12 no-scrollbar">
                    <div className="container mx-auto max-w-4xl pb-10">
                        {activeTab === 'home' && (
                            <div className="space-y-8 animate-fade-in">
                                <div className="bg-white dark:bg-gray-900 p-8 rounded-[2.5rem] shadow-sm border border-white dark:border-gray-800 relative overflow-hidden">
                                    <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-l from-brand-dark to-brand-light"></div>
                                    <div className="relative z-10 flex items-center justify-between">
                                        <div>
                                            <p className="text-[10px] text-brand-light font-black uppercase tracking-[0.2em] mb-2">{todayDate}</p>
                                            <h3 className="text-2xl font-black dark:text-white">أهلاً بك، {currentUser?.fullName.split(' ')[0]} 👋</h3>
                                            <p className="mt-3 text-xs text-gray-400 dark:text-gray-500 italic max-w-xs leading-loose">"{motivationalQuote}"</p>
                                        </div>
                                        <div className="hidden sm:flex flex-col items-center justify-center w-24 h-24 bg-gray-50 dark:bg-gray-800 rounded-3xl border dark:border-gray-700">
                                            <p className="text-[9px] font-black text-gray-400 uppercase mb-1">المهام</p>
                                            <p className="text-3xl font-black text-brand-dark dark:text-brand-light">{unreadTasksCount}</p>
                                        </div>
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                                    {[
                                        { id: 'new-report', label: 'تقرير جديد', icon: <NewReportIcon />, color: 'text-brand-light bg-brand-light/5' },
                                        { id: 'tasks', label: 'المهام', icon: <InboxIcon />, color: 'text-brand-accent-green bg-brand-accent-green/5' },
                                        { id: 'archive', label: 'الأرشيف', icon: <ArchiveBoxIcon />, color: 'text-brand-dark bg-brand-dark/5' },
                                        { id: 'profile', label: 'حسابي', icon: <UserCircleIcon />, color: 'text-brand-accent-yellow bg-brand-accent-yellow/5' }
                                    ].map(btn => (
                                        <button 
                                            key={btn.id}
                                            onClick={() => setActiveTab(btn.id)} 
                                            className="p-6 bg-white dark:bg-gray-900 rounded-[2rem] shadow-sm hover:shadow-md transition-all active:scale-95 flex flex-col items-center gap-3 border border-white dark:border-gray-800"
                                        >
                                            <div className={`p-3.5 rounded-2xl ${btn.color}`}>{btn.icon}</div>
                                            <span className="text-[11px] font-black text-gray-600 dark:text-gray-300 uppercase">{btn.label}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        {activeTab === 'tasks' && <DirectTasksView />}

                        {activeTab === 'archive' && (
                            <div className="space-y-4 animate-fade-in">
                                <div className="flex items-center justify-between px-2">
                                    <h3 className="font-black text-sm dark:text-white uppercase tracking-wider">سجل التقارير</h3>
                                    <span className="text-[10px] font-bold text-gray-400">{myReports.length} عنصر</span>
                                </div>
                                {myReports.map(r => (
                                    <ReportView key={r.id} report={r} user={currentUser!} viewerRole={Role.EMPLOYEE} onClick={() => setSelectedReport(r)} />
                                ))}
                            </div>
                        )}

                        {activeTab === 'new-report' && (
                            <form onSubmit={(e) => { e.preventDefault(); setShowSubmitConfirm(true); }} className="bg-white dark:bg-gray-900 p-8 rounded-[2.5rem] shadow-sm border border-white dark:border-gray-800 space-y-8 animate-fade-in">
                                <div className="flex justify-between items-center pb-6 border-b dark:border-gray-800">
                                    <h3 className="text-lg font-black dark:text-white">نموذج التقرير اليومي</h3>
                                    <span className="text-[10px] font-bold text-gray-400 px-3 py-1 bg-gray-50 dark:bg-gray-800 rounded-full">{new Date().toLocaleDateString('ar-EG')}</span>
                                </div>

                                <div className="space-y-4">
                                    <label className="block text-[10px] font-black text-brand-dark dark:text-brand-light uppercase tracking-widest mr-2">قائمة المهام المنجزة</label>
